import{_ as r,o as l,c as e,ai as i}from"./chunks/framework.CaiDwmc7.js";const b=JSON.parse('{"title":"Node.js 全栈开发","description":"","frontmatter":{},"headers":[],"relativePath":"tech-system/backend/nodejs-stack.md","filePath":"tech-system/backend/nodejs-stack.md"}'),s={name:"tech-system/backend/nodejs-stack.md"};function n(t,a,o,h,d,c){return l(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="node-js-全栈开发" tabindex="-1">Node.js 全栈开发 <a class="header-anchor" href="#node-js-全栈开发" aria-label="Permalink to “Node.js 全栈开发”">​</a></h1><p>Node.js 是一个基于 Chrome V8 引擎的 JavaScript 运行时环境，使开发者可以用 JavaScript 构建高性能、可扩展的服务器端应用。</p><h2 id="node-js-基础" tabindex="-1">Node.js 基础 <a class="header-anchor" href="#node-js-基础" aria-label="Permalink to “Node.js 基础”">​</a></h2><h3 id="运行时环境" tabindex="-1">运行时环境 <a class="header-anchor" href="#运行时环境" aria-label="Permalink to “运行时环境”">​</a></h3><ul><li><strong>V8 引擎</strong>: JavaScript 解析、编译、优化</li><li><strong>事件循环</strong>: 非阻塞 I/O、异步编程、高并发</li><li><strong>模块系统</strong>: CommonJS、ES Modules、模块加载</li><li><strong>包管理</strong>: npm、yarn、pnpm、版本管理</li></ul><h3 id="核心-api" tabindex="-1">核心 API <a class="header-anchor" href="#核心-api" aria-label="Permalink to “核心 API”">​</a></h3><ul><li><strong>文件系统</strong>: fs 模块、文件读写、流式处理</li><li><strong>HTTP 服务</strong>: http 模块、连接管理、请求处理</li><li><strong>事件驱动</strong>: EventEmitter、事件管理、发布订阅</li><li><strong>进程管理</strong>: child_process、多进程、工作池</li></ul><h2 id="后端框架" tabindex="-1">后端框架 <a class="header-anchor" href="#后端框架" aria-label="Permalink to “后端框架”">​</a></h2><h3 id="express-js" tabindex="-1">Express.js <a class="header-anchor" href="#express-js" aria-label="Permalink to “Express.js”">​</a></h3><ul><li><strong>基础</strong>: middleware 机制、路由定义、请求处理</li><li><strong>中间件</strong>: 身份认证、日志、错误处理、CORS</li><li><strong>性能</strong>: 连接池、缓存策略、性能优化</li><li><strong>扩展</strong>: 插件生态、第三方集成</li></ul><h3 id="nestjs" tabindex="-1">NestJS <a class="header-anchor" href="#nestjs" aria-label="Permalink to “NestJS”">​</a></h3><ul><li><strong>架构</strong>: 模块化设计、依赖注入、装饰器</li><li><strong>核心</strong>: 控制器、服务、提供者、拦截器</li><li><strong>应用</strong>: 微服务、GraphQL、WebSocket</li><li><strong>最佳实践</strong>: 测试驱动、代码生成</li></ul><h3 id="fastify" tabindex="-1">Fastify <a class="header-anchor" href="#fastify" aria-label="Permalink to “Fastify”">​</a></h3><ul><li><strong>高性能</strong>: 异步处理、流式响应、低延迟</li><li><strong>插件系统</strong>: 功能扩展、模块管理</li><li><strong>JSON Schema</strong>: 请求验证、序列化优化</li><li><strong>大规模应用</strong>: 可扩展性、生产就绪</li></ul><h2 id="数据访问" tabindex="-1">数据访问 <a class="header-anchor" href="#数据访问" aria-label="Permalink to “数据访问”">​</a></h2><h3 id="数据库驱动" tabindex="-1">数据库驱动 <a class="header-anchor" href="#数据库驱动" aria-label="Permalink to “数据库驱动”">​</a></h3><ul><li><strong>SQL 驱动</strong>: MySQL、PostgreSQL、连接管理</li><li><strong>NoSQL 驱动</strong>: MongoDB、Redis、DynamoDB</li><li><strong>ORM/ODM</strong>: TypeORM、Sequelize、Mongoose</li><li><strong>事务管理</strong>: ACID、事务处理、一致性</li></ul><h3 id="api-设计" tabindex="-1">API 设计 <a class="header-anchor" href="#api-设计" aria-label="Permalink to “API 设计”">​</a></h3><ul><li><strong>RESTful API</strong>: 资源设计、HTTP 方法、状态管理</li><li><strong>GraphQL</strong>: Schema 定义、查询优化、实时订阅</li><li><strong>gRPC</strong>: Protocol Buffers、高性能通信、流式处理</li><li><strong>版本管理</strong>: API 版本控制、向后兼容、迁移策略</li></ul><h2 id="异步编程" tabindex="-1">异步编程 <a class="header-anchor" href="#异步编程" aria-label="Permalink to “异步编程”">​</a></h2><h3 id="异步模式" tabindex="-1">异步模式 <a class="header-anchor" href="#异步模式" aria-label="Permalink to “异步模式”">​</a></h3><ul><li><strong>Callbacks</strong>: 回调函数、error-first 模式</li><li><strong>Promises</strong>: 状态管理、链式调用、错误处理</li><li><strong>Async/Await</strong>: 代码可读性、错误处理、流程控制</li><li><strong>RxJS</strong>: 响应式编程、流处理、操作符</li></ul><h3 id="并发控制" tabindex="-1">并发控制 <a class="header-anchor" href="#并发控制" aria-label="Permalink to “并发控制”">​</a></h3><ul><li><strong>队列管理</strong>: 任务队列、优先级、背压处理</li><li><strong>资源池</strong>: 连接池、线程池、工作线程</li><li><strong>限流降级</strong>: 令牌桶、漏桶、熔断</li></ul><h2 id="测试与调试" tabindex="-1">测试与调试 <a class="header-anchor" href="#测试与调试" aria-label="Permalink to “测试与调试”">​</a></h2><h3 id="单元测试" tabindex="-1">单元测试 <a class="header-anchor" href="#单元测试" aria-label="Permalink to “单元测试”">​</a></h3><ul><li><strong>框架</strong>: Jest、Mocha、Vitest</li><li><strong>断言库</strong>: Chai、Expect、Should</li><li><strong>Mock</strong>: Sinon、jest.mock、模拟数据</li><li><strong>覆盖率</strong>: 代码覆盖、质量指标</li></ul><h3 id="调试工具" tabindex="-1">调试工具 <a class="header-anchor" href="#调试工具" aria-label="Permalink to “调试工具”">​</a></h3><ul><li><strong>Chrome DevTools</strong>: 远程调试、性能分析</li><li><strong>Node Inspector</strong>: 命令行调试、断点调试</li><li><strong>日志框架</strong>: Winston、Pino、Bunyan</li><li><strong>性能监控</strong>: 内存泄漏、CPU 分析、火焰图</li></ul><h2 id="部署与运维" tabindex="-1">部署与运维 <a class="header-anchor" href="#部署与运维" aria-label="Permalink to “部署与运维”">​</a></h2><h3 id="容器化" tabindex="-1">容器化 <a class="header-anchor" href="#容器化" aria-label="Permalink to “容器化”">​</a></h3><ul><li><strong>Docker</strong>: 镜像构建、容器打包、镜像优化</li><li><strong>多阶段构建</strong>: 缩小镜像体积、构建优化</li><li><strong>Docker Compose</strong>: 本地开发、环境一致性</li></ul><h3 id="进程管理" tabindex="-1">进程管理 <a class="header-anchor" href="#进程管理" aria-label="Permalink to “进程管理”">​</a></h3><ul><li><strong>PM2</strong>: 进程守护、负载均衡、集群模式</li><li><strong>systemd</strong>: 服务管理、系统集成</li><li><strong>守护进程</strong>: 自动重启、日志管理、监控</li></ul><h3 id="云部署" tabindex="-1">云部署 <a class="header-anchor" href="#云部署" aria-label="Permalink to “云部署”">​</a></h3><ul><li><strong>Heroku/Vercel</strong>: 云平台部署、自动化部署</li><li><strong>AWS Lambda</strong>: Serverless 函数、事件驱动</li><li><strong>Kubernetes</strong>: 容器编排、自动扩容、服务发现</li></ul><h2 id="完整技术栈" tabindex="-1">完整技术栈 <a class="header-anchor" href="#完整技术栈" aria-label="Permalink to “完整技术栈”">​</a></h2><h3 id="mean-stack" tabindex="-1">MEAN Stack <a class="header-anchor" href="#mean-stack" aria-label="Permalink to “MEAN Stack”">​</a></h3><ul><li>MongoDB、Express、Angular、Node.js</li><li>全 JavaScript 栈、端到端开发</li></ul><h3 id="mern-stack" tabindex="-1">MERN Stack <a class="header-anchor" href="#mern-stack" aria-label="Permalink to “MERN Stack”">​</a></h3><ul><li>MongoDB、Express、React、Node.js</li><li>现代化前后端分离架构</li></ul><h3 id="pern-stack" tabindex="-1">PERN Stack <a class="header-anchor" href="#pern-stack" aria-label="Permalink to “PERN Stack”">​</a></h3><ul><li>PostgreSQL、Express、React、Node.js</li><li>企业级应用架构</li></ul><h2 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to “最佳实践”">​</a></h2><h3 id="代码组织" tabindex="-1">代码组织 <a class="header-anchor" href="#代码组织" aria-label="Permalink to “代码组织”">​</a></h3><ul><li>分层架构、模块化设计、关注分离</li><li>路由、中间件、服务、数据访问层</li></ul><h3 id="性能优化" tabindex="-1">性能优化 <a class="header-anchor" href="#性能优化" aria-label="Permalink to “性能优化”">​</a></h3><ul><li>缓存策略、数据库查询优化</li><li>连接复用、流式传输、压缩传输</li></ul><h3 id="安全实践" tabindex="-1">安全实践 <a class="header-anchor" href="#安全实践" aria-label="Permalink to “安全实践”">​</a></h3><ul><li>输入验证、认证授权、加密存储</li><li>依赖管理、漏洞扫描、安全审计</li></ul>',50)])])}const m=r(s,[["render",n]]);export{b as __pageData,m as default};
